#include <iostream>   // include the I/O library
using namespace std;  // so we don't have to type std::

int main() {
    cout << "Hello, world! 🌸" << endl;
    return 0;
}

To compile and run:
  g++ hello.cpp -o hello     <- compile
  ./hello                     <- run

Breaking it down:
  #include    brings in a library
  main()      entry point, returns int
  cout <<     print to console
  endl        newline + flush buffer
  return 0    tells OS: success

Modern C++ (use -std=c++17 or c++20 flag):
  g++ hello.cpp -o hello -std=c++17

Fundamental types:
  int       integer           int x = 42;
  long      big integer       long n = 1000000L;
  float     decimal           float f = 3.14f;
  double    precise decimal   double pi = 3.14159;
  bool      true/false        bool ok = true;
  char      single character  char c = 'A';
  string    text (with STL)   string s = "hello";

auto — compiler deduces type:
  auto x = 42;       // int
  auto y = 3.14;     // double
  auto s = "hello";  // const char*

Const:
  const int MAX = 100;   // cannot be changed

Type casting:
  double d = 3.9;
  int x = (int) d;       // x = 3, truncated
  int x = static_cast<int>(d);  // modern way

This is what makes C++ unique and powerful.

Pointers — store memory addresses:
  int x = 42;
  int* ptr = &x;    // ptr holds address of x
  cout << ptr;      // prints the address
  cout << *ptr;     // prints 42 (dereference)
  *ptr = 99;        // changes x to 99!

References — an alias for a variable:
  int x = 42;
  int& ref = x;     // ref IS x
  ref = 99;         // x is now 99

Why pointers matter:
  void addOne(int* n) {
      (*n)++;       // modify the actual variable
  }
  int x = 5;
  addOne(&x);       // x is now 6

Nullptr (modern, use instead of NULL):
  int* ptr = nullptr;
  if (ptr != nullptr) { ... }

Avoid memory leaks:
  int* arr = new int[10];   // allocate
  delete[] arr;             // MUST free!

C++ classes are similar to Java but with more control:

class Dog {
private:
    string name;   // only accessible inside class
    int age;

public:
    // constructor
    Dog(string n, int a) : name(n), age(a) {}

    // destructor — runs when object is destroyed
    ~Dog() { cout << name << " goodbye" << endl; }

    void bark() {
        cout << name << " says: Woof!" << endl;
    }

    string getName() { return name; }  // getter
};

Using it:
  Dog d("Luna", 3);      // on the stack (auto-deleted)
  d.bark();

  Dog* dp = new Dog("Mochi", 2);  // on the heap
  dp->bark();            // -> dereferences pointer
  delete dp;             // MUST delete!

Inheritance:
  class Puppy : public Dog {
  public:
      Puppy(string n) : Dog(n, 0) {}
  };

The STL gives you powerful containers and algorithms.

vector — dynamic array:
  #include <vector>
  vector<int> v = {1, 2, 3};
  v.push_back(4);
  v[0];              // 1
  v.size();          // 4
  v.pop_back();      // removes last

map — key-value pairs (sorted):
  #include <map>
  map<string, int> scores;
  scores["alice"] = 90;
  scores["bob"]   = 85;
  scores["alice"]; // 90

set — unique sorted values:
  #include <set>
  set<int> s = {3, 1, 2, 1};
  // contains: 1 2 3 (sorted, no duplicates)

algorithms:
  #include <algorithm>
  sort(v.begin(), v.end());
  reverse(v.begin(), v.end());
  auto it = find(v.begin(), v.end(), 3);

Range-based for loop:
  for (auto& item : v) {
      cout << item << endl;
  }

C++11 and beyond added many quality-of-life features:

auto type deduction:
  auto x = 42;          // don't repeat yourself
  auto it = v.begin();

Range-based for:
  for (const auto& s : strings) { ... }

Lambdas — anonymous functions:
  auto add = [](int a, int b) { return a + b; };
  cout << add(3, 4);   // 7

  sort(v.begin(), v.end(), [](int a, int b) {
      return a > b;    // sort descending
  });

Structured bindings (C++17):
  auto [key, val] = *map.begin();

String literals:
  string s = "Hello"s;      // std::string directly
  auto raw = R"(raw \n string)";

Nullptr:
  int* p = nullptr;   // always use this, not NULL

Compile with:
  g++ file.cpp -o out -std=c++17 -Wall -O2
